/// <summary>
/// Data contract class for the Unsold Journal Check Post process in the ETGSPAIN model.
/// </summary>
[
    DataContract,
    SysOperationContractProcessing(classStr(ETGSPAINUnsoldJournalCheckPostUIBuilder))
]
class ETGSPAINUnsoldJournalCheckPostContract
{
    ETGSPAINUnsoldJournalId etgspainUnsoldJournalId;
    Args                    args;   

}

Method.Source:
/// <summary>
/// Gets or sets the unsold journal ID.
/// </summary>
/// <param name="_etgspainUnsoldJournalId">The ID of the unsold journal.</param>
/// <returns>Returns the unsold journal ID.</returns>
[DataMember]
public ETGSPAINUnsoldJournalId parmETGSPAINUnsoldJournalId(ETGSPAINUnsoldJournalId _etgspainUnsoldJournalId = etgspainUnsoldJournalId)
{
    etgspainUnsoldJournalId = _etgspainUnsoldJournalId;
    return etgspainUnsoldJournalId;
}

    /// <summary>
    /// Gets or sets the Args object for the process.
    /// </summary>
    /// <param name="_args">The arguments for the process.</param>
    /// <returns>Returns the Args object.</returns>
    public Args parmArgs(Args _args = args)
	{
		args = _args;
		return args;
	}
